const item = $input.first().json;
const body = item.body || item;
const message = body.message || {};

const toolCall =
  (message.toolCalls && message.toolCalls[0]) ||
  (message.toolCallList && message.toolCallList[0]) ||
  null;

const args = toolCall?.function?.arguments || 
             toolCall?.parameters || {};
const toolCallId = toolCall?.id || "";

return [{
  json: {
    toolCallId,
    date: args.date || "",
    time: args.time || "",
    guests: args.guests || "",
    name: args.name || "",
    phone: args.phone || "",
    email: args.email || "",
    booking_type: args.booking_type || ""
  }
}];

const input = $('Code in JavaScript').first().json;

const toolCallId = input.toolCallId || "";
const name = input.name || "";
const date = input.date || "";
const time = input.time || "";
const guests = input.guests || "";
const type = input.booking_type || "";

return [{
  json: {
    results: [{
      name: "bookEvent",
      toolCallId: toolCallId,
      result: `Brilliant! Your ${type} table for ${guests} guests on ${date} at ${time} has been booked, ${name}. A confirmation email is on its way to you now!`
    }]
  }
}];
